func (u *userSvc) UpdateUser(ctx context.Context, req *UpdateUserRequest) (*UpdateUserResponse, error) {
	if req == nil || strings.TrimSpace(req.Id) == "" {
		return nil, status.Error(codes.InvalidArgument, "id is required")
	}
	u.st.mu.Lock()
	defer u.st.mu.Unlock()

	user, ok := u.st.users[req.Id]
	if !ok {
		return nil, status.Error(codes.NotFound, "user not found")
	}

	if req.Email != "" {
		if !validateEmail(req.Email) {
			return nil, status.Error(codes.InvalidArgument, "invalid email")
		}
		for _, existing := range u.st.users {
			if existing.Id != user.Id && strings.EqualFold(existing.Email, req.Email) {
				return nil, status.Error(codes.AlreadyExists, "email already exists")
			}
		}
		user.Email = strings.TrimSpace(req.Email)
	}
	if req.Name != "" {
		user.Name = strings.TrimSpace(req.Name)
	}
	user.UpdatedAt = nowUnix()
	return &UpdateUserResponse{User: cloneUser(user)}, nil
}

func (u *userSvc) DeleteUser(ctx context.Context, req *DeleteUserRequest) (*DeleteUserResponse, error) {
	if req == nil || strings.TrimSpace(req.Id) == "" {
		return nil, status.Error(codes.InvalidArgument, "id is required")
	}
	u.st.mu.Lock()
	defer u.st.mu.Unlock()

	if _, ok := u.st.users[req.Id]; !ok {
		return nil, status.Error(codes.NotFound, "user not found")
	}
	delete(u.st.users, req.Id)

	for oid, o := range u.st.orders {
		if o.UserId == req.Id {
			delete(u.st.orders, oid)
			for pid, p := range u.st.payments {
				if p.OrderId == oid {
					delete(u.st.payments, pid)
				}
			}
		}
	}

	return &DeleteUserResponse{Deleted: true}, nil
}

