func (p *paymentSvc) CreatePayment(ctx context.Context, req *CreatePaymentRequest) (*CreatePaymentResponse, error) {
	if req == nil {
		return nil, status.Error(codes.InvalidArgument, "request is nil")
	}
	if strings.TrimSpace(req.OrderId) == "" {
		return nil, status.Error(codes.InvalidArgument, "order_id is required")
	}
	if req.Amount <= 0 {
		return nil, status.Error(codes.InvalidArgument, "amount must be > 0")
	}
	cur := strings.ToUpper(strings.TrimSpace(req.Currency))
	if cur == "" {
		cur = "USD"
	}
	method := strings.ToUpper(strings.TrimSpace(req.Method))
	if method == "" {
		method = "CARD"
	}

	p.st.mu.Lock()
	defer p.st.mu.Unlock()

	order, ok := p.st.orders[req.OrderId]
	if !ok {
		return nil, status.Error(codes.NotFound, "order not found")
	}
	if order.Currency != cur {
		return nil, status.Error(codes.FailedPrecondition, "currency mismatch with order")
	}
	if req.Amount != order.Amount {
		return nil, status.Error(codes.FailedPrecondition, "amount mismatch with order")
	}

	id := p.st.nextID("pay", &p.st.paySeq)
	ts := nowUnix()
	payment := &Payment{
		Id:        id,
		OrderId:   req.OrderId,
		Amount:    req.Amount,
		Currency:  cur,
		Status:    "AUTHORIZED",
		Method:    method,
		CreatedAt: ts,
		UpdatedAt: ts,
	}
	p.st.payments[id] = payment
	return &CreatePaymentResponse{Payment: clonePayment(payment)}, nil
}

